// Firecrawl crawl poller - polls GET /v1/crawl/{id} every 5s, max 60 iterations
const maxIterations = 60;
const pollIntervalMs = 5000;

const item = $input.first();
const crawlId = item.json && item.json.id;

if (!crawlId) {
  const errMsg = item.json && item.json.error ? item.json.error : 'No crawl ID returned from Firecrawl';
  return [{ json: { crawlSuccess: false, error: errMsg } }];
}

// Access Firecrawl credential for the API token
try {
  const credential = $credentials['Firecrawl API'];
  const authValue = credential.value || credential.httpHeaderAuth?.value || '';
  const apiKey = authValue.replace('Bearer ', '').trim();

  if (!apiKey) {
    return [{ json: { crawlSuccess: false, error: 'Firecrawl API key not found in credential' } }];
  }

  for (let i = 0; i < maxIterations; i++) {
    try {
      const response = await this.helpers.request({
        method: 'GET',
        uri: `https://api.firecrawl.dev/v1/crawl/${crawlId}`,
        headers: { 'Authorization': `Bearer ${apiKey}` },
        json: true
      });

      if (response.status === 'completed') {
        const pages = response.pages || response.data || [];
        return [{
          json: {
            crawlSuccess: true,
            crawlData: response.data || [],
            pages: pages,
            pageCount: pages.length
          }
        }];
      }

      if (response.status === 'failed' || response.status === 'error') {
        const errMsg = response.error || response.message || `Crawl failed with status: ${response.status}`;
        return [{ json: { crawlSuccess: false, error: errMsg } }];
      }

      // Still running - continue polling
    } catch (pollErr) {
      // Transient HTTP error on last iteration
      if (i === maxIterations - 1) {
        return [{ json: { crawlSuccess: false, error: `Polling HTTP error: ${pollErr.message}` } }];
      }
    }

    await new Promise(resolve => setTimeout(resolve, pollIntervalMs));
  }

  return [{ json: { crawlSuccess: false, error: `Crawl polling timed out after ${maxIterations} iterations (${(maxIterations * pollIntervalMs) / 1000}s)` } }];
} catch (err) {
  return [{ json: { crawlSuccess: false, error: `Code node error: ${err.message}` } }];
}
